function n(t,e="INR"){return new Intl.NumberFormat("en-IN",{style:"currency",currency:e,maximumFractionDigits:0}).format(Number(t)||0)}function r(t){return new Intl.DateTimeFormat("en-IN",{day:"2-digit",month:"short",year:"numeric"}).format(new Date(t))}function a(t){return new Intl.DateTimeFormat("en-IN",{month:"short",year:"2-digit"}).format(new Date(t))}export{r as a,n as f,a as m};
